    }





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<WalletSdkException> {
        override fun lift(error_buf: RustBuffer.ByValue): WalletSdkException = FfiConverterTypeWalletSdkError.lift(error_buf)
    }


}

/**
 * @suppress
 */
public object FfiConverterTypeWalletSdkError : FfiConverterRustBuffer<WalletSdkException> {
    override fun read(buf: ByteBuffer): WalletSdkException {


        return when(buf.getInt()) {
            1 -> WalletSdkException.InvalidProfile()
            2 -> WalletSdkException.InvalidRequest()
            3 -> WalletSdkException.MalformedStatus()
            4 -> WalletSdkException.StaleStatus()
            5 -> WalletSdkException.IndexerUnavailable()
            6 -> WalletSdkException.WrongProtocolIdentity()
            7 -> WalletSdkException.InvalidTransaction()
            8 -> WalletSdkException.InsufficientFunds()
            9 -> WalletSdkException.NonceBoundary()
            10 -> WalletSdkException.FeeBoundary()
            11 -> WalletSdkException.ReviewMismatch()
            12 -> WalletSdkException.SubmissionRejected()
            13 -> WalletSdkException.MalformedSubmitResponse()
            14 -> WalletSdkException.TxidMismatch()
            15 -> WalletSdkException.InvalidObservation()
            16 -> WalletSdkException.InsufficientQuorum()
            17 -> WalletSdkException.CheckpointRegression()
            18 -> WalletSdkException.CheckpointConflict()
            19 -> WalletSdkException.InvalidPersistedState()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: WalletSdkException): ULong {
        return when(value) {
            is WalletSdkException.InvalidProfile -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is WalletSdkException.InvalidRequest -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is WalletSdkException.MalformedStatus -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
