            )
        }
    }

    override fun write(value: WalletSdkException, buf: ByteBuffer) {
        when(value) {
            is WalletSdkException.InvalidProfile -> {
                buf.putInt(1)
                Unit
            }
            is WalletSdkException.InvalidRequest -> {
                buf.putInt(2)
                Unit
            }
            is WalletSdkException.MalformedStatus -> {
                buf.putInt(3)
                Unit
            }
            is WalletSdkException.StaleStatus -> {
                buf.putInt(4)
                Unit
            }
            is WalletSdkException.IndexerUnavailable -> {
                buf.putInt(5)
                Unit
            }
            is WalletSdkException.WrongProtocolIdentity -> {
                buf.putInt(6)
                Unit
            }
            is WalletSdkException.InvalidTransaction -> {
                buf.putInt(7)
                Unit
            }
            is WalletSdkException.InsufficientFunds -> {
                buf.putInt(8)
                Unit
            }
            is WalletSdkException.NonceBoundary -> {
                buf.putInt(9)
                Unit
            }
            is WalletSdkException.FeeBoundary -> {
                buf.putInt(10)
                Unit
            }
            is WalletSdkException.ReviewMismatch -> {
                buf.putInt(11)
                Unit
            }
            is WalletSdkException.SubmissionRejected -> {
                buf.putInt(12)
                Unit
            }
            is WalletSdkException.MalformedSubmitResponse -> {
                buf.putInt(13)
                Unit
            }
            is WalletSdkException.TxidMismatch -> {
                buf.putInt(14)
                Unit
            }
            is WalletSdkException.InvalidObservation -> {
                buf.putInt(15)
                Unit
            }
            is WalletSdkException.InsufficientQuorum -> {
                buf.putInt(16)
                Unit
            }
            is WalletSdkException.CheckpointRegression -> {
                buf.putInt(17)
                Unit
            }
            is WalletSdkException.CheckpointConflict -> {
                buf.putInt(18)
                Unit
            }
            is WalletSdkException.InvalidPersistedState -> {
                buf.putInt(19)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalUInt: FfiConverterRustBuffer<kotlin.UInt?> {
    override fun read(buf: ByteBuffer): kotlin.UInt? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterUInt.read(buf)
    }

    override fun allocationSize(value: kotlin.UInt?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterUInt.allocationSize(value)
        }
    }

    override fun write(value: kotlin.UInt?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterUInt.write(value, buf)
        }
    }
}




